import pandas as pd# Path to the filefile_path = '/Users/nb/Desktop/metaphlan_db_meta4_combined_reports.txt'# Load the datadata = pd.read_csv(file_path, sep='\t')# Columns to removecolumns_to_remove = ['AK1304', 'PP2368', 'HK2340']# Remove specified columns if they exist in the DataFramedata = data.drop(columns=[col for col in columns_to_remove if col in data.columns])# Save the modified data to the same directoryoutput_path = '/Users/nb/Desktop/modified_metaphlan_db_meta4_combined_reports.txt'data.to_csv(output_path, sep='\t', index=False)print("Columns removed and modified file saved to", output_path)